        public void CheckInto(string bin, string op, string arg)
        {
            AssertDecode(bin, op, arg);
        }
        
        /// <summary>
        /// Interrupt Return
        /// <remarks>RETI</remarks>
        /// </summary>
        [Theory]
        [InlineData("11001111", "IRET", "")]
        public void CheckIret(string bin, string op, string arg)
        {
            AssertDecode(bin, op, arg);
        }
    }
    
